// --- Helpers ---

/** Find the ticket link for an event by fuzzy name match */
export function findTicketLink(eventName: string): TicketLink | undefined {
  const q = eventName.toLowerCase();
  return ticketLinks.find((t) => {
    const tn = t.event.toLowerCase();
    return tn.includes(q) || q.includes(tn) || q.split(" ").slice(0, 3).join(" ") === tn.split(" ").slice(0, 3).join(" ");
  });
}

/** Find music link by artist name appearing in event name */
export function findMusicLink(eventName: string): MusicLink | undefined {
  const q = eventName.toLowerCase();
  return musicLinks.find((m) => q.includes(m.artist.toLowerCase()));
}

/** Find restaurant link by spot name */
export function findRestaurantLink(spotName: string): RestaurantLink | undefined {
  const q = spotName.toLowerCase();
  return restaurantLinks.find((r) => r.name.toLowerCase() === q || q.includes(r.name.toLowerCase()) || r.name.toLowerCase().includes(q));
}

/** Get prediction for a team */
export function findTeamPrediction(teamName: string): TeamPrediction | undefined {
  return teamPredictions.find((p) => p.team === teamName);
}

// Search helper
export function searchAll(query: string): { events: PhillyEvent[]; spots: HotSpot[]; influencers: Influencer[]; teams: SportsTeam[] } {
  const q = query.toLowerCase().trim();
  if (!q) return { events: [], spots: [], influencers: [], teams: [] };
  return {
    events: events.filter(e =>
      e.name.toLowerCase().includes(q) ||
      e.venue.toLowerCase().includes(q) ||
      e.neighborhood.toLowerCase().includes(q) ||
      e.category.toLowerCase().includes(q) ||
      e.vibeTag.toLowerCase().includes(q)
    ),
    spots: hotspots.filter(s =>
      s.name.toLowerCase().includes(q) ||
      s.neighborhood.toLowerCase().includes(q) ||
      s.type.toLowerCase().includes(q) ||
      (s.cuisine && s.cuisine.toLowerCase().includes(q)) ||
      s.vibeTag.toLowerCase().includes(q)
    ),
    influencers: influencers.filter(i =>
      i.name.toLowerCase().includes(q) ||
      i.handle.toLowerCase().includes(q) ||
      i.focus.toLowerCase().includes(q)
    ),
    teams: sportsTeams.filter(t =>
      t.team.toLowerCase().includes(q) ||
      t.league.toLowerCase().includes(q) ||
      t.venue.toLowerCase().includes(q)
    ),
  };
}
